    pub epoch: u64,
}

impl State {
    pub fn new() -> Self {
        Self {
            entries: Vec::new(),
            active: BTreeMap::new(),
            handles: BTreeMap::new(),
            last_seen: BTreeMap::new(),
            next_handle: 1,
            epoch: 0,
        }
    }

    pub fn key_for(slot: &str, path: &str, symbol: &str) -> String {
